SELECT clip_type
FROM clips
WHERE clip_id = '0';

SELECT clip_id
FROM clips
WHERE data_quality_score = (SELECT MAX(data_quality_score) FROM clips);

SELECT clip_id, data_quality_score
FROM clips
WHERE data_quality_score > (SELECT AVG(data_quality_score) FROM clips);

SELECT AVG(data_quality_score) AS avg_quality_score, COUNT(*) AS total_clips
FROM clips
WHERE subplot_id = 1;

SELECT AVG(data_quality_score) AS average_quality_score
FROM clips
WHERE status = 'valid';

SELECT file_path
FROM clip_metadata
WHERE clip_id = '1';

SELECT upload_user_id, COUNT(*) AS number_of_attachments
FROM clip_attachments
GROUP BY upload_user_id;

SELECT file_size
FROM clip_attachments
WHERE upload_user_id = 1;

SELECT status, COUNT(*) as total_clips
FROM clips
GROUP BY status;

SELECT AVG(file_size) AS average_weight, COUNT(*) AS total_stack
FROM clip_metadata
WHERE data_integrity_check = 1;
